import assert from 'node:assert/strict';
import test from 'node:test';
import {
  UNIVERSAL_EPOCH_SECONDS_AT_UNIX_EPOCH,
  gnosisUniversalEpochClock,
  secondsSinceUniversalEpoch,
} from './universal-epoch-clock';

test('secondsSinceUniversalEpoch anchors Unix epoch to the fixed cosmic offset', () => {
  assert.equal(secondsSinceUniversalEpoch(0), UNIVERSAL_EPOCH_SECONDS_AT_UNIX_EPOCH);
});

test('secondsSinceUniversalEpoch is deterministic and monotonic in milliseconds', () => {
  const t0 = 1_750_000_000_000;
  const first = secondsSinceUniversalEpoch(t0);
  const second = secondsSinceUniversalEpoch(t0);
  const plusOneSecond = secondsSinceUniversalEpoch(t0 + 1_000);

  assert.equal(first, second);
  assert.equal(plusOneSecond - first, 1n);
});

test('gnosisUniversalEpochClock returns a stable quasicrystalline vector payload', () => {
  const t0 = 1_750_000_000_000;
  const first = gnosisUniversalEpochClock(t0);
  const second = gnosisUniversalEpochClock(t0);

  assert.equal(first.epoch, 'universal-epoch');
  assert.equal(
    first.secondsSinceUniversalEpoch,
    second.secondsSinceUniversalEpoch
  );
  assert.equal(first.unixSeconds, second.unixSeconds);
  assert.deepEqual(first.vectorClock, second.vectorClock);

  assert.doesNotThrow(() => {
    BigInt(first.secondsSinceUniversalEpoch);
    BigInt(first.unixSeconds);
    BigInt(first.vectorClock.phi);
    BigInt(first.vectorClock.pell);
    BigInt(first.vectorClock.trib);
    BigInt(first.vectorClock.moment);
  });
});
